template.css:
.card {
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  box-shadow: none;
}

.product02-card {
  display: flex;
  flex-direction: column;
  color: #6B4F3A;
}

.product02-title {
  margin: 0 0 12px;
  font-size: var(--title-font-size, 20px);
  font-weight: var(--title-font-weight, 600);
  color: var(--title-color, #6B4F3A);
  line-height: var(--title-line-height, 1.3);
}

.product02-list {
  list-style: none;
  padding: 0;
  margin: 0 0 24px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.product02-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  font-size: var(--description-font-size, 14px);
  font-weight: var(--description-font-weight, 400);
  color: var(--description-color, #5A646A);
  line-height: var(--description-line-height, 1.6);
}

.product02-item:has(.product02-text:empty) {
  display: none;
}

.product02-dot {
  width: 4px;
  height: 4px;
  border-radius: 9999px;
  background: #C56A4A;
  margin-top: 9px;
  flex-shrink: 0;
}

.product02-text:empty::before {
  content: ' ';
}

.product02-button {
  width: 100%;
  height: 44px;
  border-radius: 12px;
  border: 1px solid rgba(107, 79, 58, 0.2);
  background: transparent;
  color: var(--button-color, #6B4F3A);
  font-size: var(--button-font-size, 14px);
  font-weight: var(--button-font-weight, 500);
  cursor: pointer;
  transition: background 0.2s ease, border-color 0.2s ease;
}

.product02-button:hover {
  background: rgba(107, 79, 58, 0.05);
  border-color: rgba(107, 79, 58, 0.3);
}

[dir="rtl"] .product02-item {
  flex-direction: row-reverse;
}

[dir="rtl"] .product02-card {
  text-align: right;
}

@supports not selector(:has(*)) {
  .product02-text:empty {
    display: none;
  }
  .product02-text:empty + .product02-dot,
  .product02-item:empty {
    display: none;
  }
}
